import anthropic, json, hashlib

client = anthropic.Anthropic()

SPEC_COVERAGE_TOOL = {
    "name": "audit_spec_coverage",
    "description": "Audit a behaviour spec for completeness against a requirement list",
    "input_schema": {
        "type": "object",
        "required": ["gaps", "missing_test_signals", "coverage_pct", "verdict"],
        "properties": {
            "gaps": {
                "type": "array",
                "description": "Requirements with no must-do item",
                "items": {"type": "string"}
            },
            "missing_test_signals": {
                "type": "array",
                "description": "must-do items that lack a test_signal",
                "items": {"type": "string"}
            },
            "coverage_pct": {
                "type": "number",
                "description": "% of requirements covered by ≥1 testable must-do"
            },
            "verdict": {"enum": ["GREEN", "YELLOW", "RED"]},
            "notes": {"type": "string"}
        }
    }
}

def audit_spec_coverage(requirements, behaviour_spec):
    response = client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=1024,
        tools=[SPEC_COVERAGE_TOOL],
        tool_choice={"type": "tool", "name": "audit_spec_coverage"},
        messages=[{
            "role": "user",
            "content": (
                f"Audit this behaviour spec for coverage.\n\n"
                f"Requirements:\n{json.dumps(requirements, indent=2)}\n\n"
                f"Behaviour spec:\n{json.dumps(behaviour_spec, indent=2)}\n\n"
                "Rules: coverage_pct = requirements with ≥1 must-do with test_signal / total * 100. "
                "Verdict: GREEN if coverage_pct == 100 and no missing test_signals, "
                "YELLOW if coverage_pct >= 80, RED otherwise."
            )
        }]
    )
    for block in response.content:
        if block.type == "tool_use":
            return block.input
    raise RuntimeError("No tool use in response")

