import anthropic, json, hashlib

client = anthropic.Anthropic()

PROMPT_QUALITY_TOOL = {
    "name": "audit_prompt_quality",
    "description": "Audit the quality and traceability of a system prompt",
    "input_schema": {
        "type": "object",
        "required": ["hash_match", "token_count", "within_budget",
                     "spec_alignment_score", "verdict", "issues"],
        "properties": {
            "hash_match": {
                "type": "boolean",
                "description": "True if SHA-256 of prompt matches the hash in prompt_registry.json"
            },
            "token_count": {"type": "integer"},
            "within_budget": {
                "type": "boolean",
                "description": "True if token_count <= model context limit minus expected conversation overhead"
            },
            "spec_alignment_score": {
                "type": "number",
                "description": "0-1: fraction of must-do items that are reflected in the prompt"
            },
            "verdict": {"enum": ["GREEN", "YELLOW", "RED"]},
            "issues": {"type": "array", "items": {"type": "string"}}
        }
    }
}

def audit_prompt_quality(system_prompt, behaviour_spec, prompt_registry):
    current_hash = hashlib.sha256(system_prompt.encode()).hexdigest()
    registered_hash = prompt_registry.get("current_hash", "")
    hash_match = current_hash == registered_hash

    response = client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=1024,
        tools=[PROMPT_QUALITY_TOOL],
        tool_choice={"type": "tool", "name": "audit_prompt_quality"},
        messages=[{
            "role": "user",
            "content": (
                f"Audit this system prompt against the behaviour spec.\n\n"
                f"System prompt (first 1000 chars):\n{system_prompt[:1000]}\n\n"
                f"Behaviour spec must-do items:\n{json.dumps([s for s in behaviour_spec if s['type']=='must_do'], indent=2)}\n\n"
                f"Hash match with registry: {hash_match}\n\n"
                "spec_alignment_score = fraction of must-do items explicitly addressed in the prompt. "
                "Verdict: RED if hash_match=False (prompt edited since last eval). "
                "RED if spec_alignment_score < 0.8. GREEN otherwise."
            )
        }]
    )
    for block in response.content:
        if block.type == "tool_use":
            return block.input
    raise RuntimeError("No tool use in response")

import anthropic, json, asyncio

client = anthropic.Anthropic()

SIGN_OFF_TOOL = {
    "name": "generate_sign_off_report",
    "description": "Produce a consolidated design sign-off report from six dimension audits",
    "input_schema": {
        "type": "object",
        "required": ["overall_verdict", "dimension_results", "blocking_issues",
                     "sign_off_status", "reviewer_notes"],
        "properties": {
            "overall_verdict": {"enum": ["APPROVED", "APPROVED_WITH_CONDITIONS", "BLOCKED"]},
            "dimension_results": {
                "type": "object",
                "properties": {
                    "behaviour_spec": {"enum": ["GREEN", "YELLOW", "RED"]},
                    "eval_plan": {"enum": ["GREEN", "YELLOW", "RED"]},
                    "risk_ethics": {"enum": ["GREEN", "YELLOW", "RED"]},
                    "prototype_evidence": {"enum": ["GREEN", "YELLOW", "RED"]},
                    "prompt_quality": {"enum": ["GREEN", "YELLOW", "RED"]},
                    "operational_readiness": {"enum": ["GREEN", "YELLOW", "RED"]}
                }
            },
            "blocking_issues": {
                "type": "array",
                "description": "Issues that must be resolved before sign-off",
                "items": {"type": "string"}
            },
            "sign_off_status": {
                "enum": ["SIGNED_OFF", "PENDING_RESOLUTION", "REJECTED"]
            },
            "reviewer_notes": {"type": "string"}
        }
    }
}

def generate_sign_off_report(audit_results: dict) -> dict:
    """
    audit_results: dict with keys matching the six dimensions,
    each value is the output of the corresponding audit function.
    """
    response = client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=2048,
        tools=[SIGN_OFF_TOOL],
        tool_choice={"type": "tool", "name": "generate_sign_off_report"},
        messages=[{
            "role": "user",
            "content": (
                f"Consolidate these dimension audit results into a sign-off report.\n\n"
                f"{json.dumps(audit_results, indent=2)}\n\n"
                "Rules:\n"
                "- APPROVED: all dimensions GREEN\n"
                "- APPROVED_WITH_CONDITIONS: ≥1 YELLOW, no RED\n"
                "- BLOCKED: any RED dimension\n"
                "sign_off_status: SIGNED_OFF if APPROVED, PENDING_RESOLUTION if WITH_CONDITIONS, "
                "REJECTED if BLOCKED."
            )
        }]
    )
    for block in response.content:
        if block.type == "tool_use":
            return block.input
    raise RuntimeError("No tool use in response")


def run_design_review(
    requirements, behaviour_spec, eval_plan,
    fmea_results, data_policy, prototype_evidence,
    system_prompt, prompt_registry, operational_plan
):
    # In a real implementation, these six calls run in parallel
    audit_results = {
        "behaviour_spec": {"verdict": "GREEN", "coverage_pct": 100},
        "eval_plan": {"verdict": "GREEN", "uncovered_must_dos": [], "is_automated": True},
        "risk_ethics": {"verdict": "YELLOW", "blocking_issues": ["Bias audit not yet complete"]},
        "prototype_evidence": {"verdict": "GREEN", "blocking_issues": []},
        "prompt_quality": {"verdict": "GREEN", "hash_match": True, "spec_alignment_score": 0.95},
        "operational_readiness": {"verdict": "GREEN", "blocking_issues": []}
    }
    report = generate_sign_off_report(audit_results)
    return report
